SMOKE_CHARS = ["▓", "▒", "░", " "]


def add_smoke(lines, offset):
    result = list(lines)
    for i in range(3):
        row = 8 + i
        col = 75 + i + offset
        if row < len(result) and col < len(result[row]):
            l = list(result[row])
            l[col] = SMOKE_CHARS[(offset + i) % 4]
            result[row] = "".join(l)
    return result


def animate_banner(duration=2.0):
    with Live(console=console, refresh_per_second=10, transient=True, screen=False) as live:
        for step in range(20):
            lines = add_smoke(CROW, step % 4)
            art = "\n".join(lines)
            t = Text(
                f"[bright_white]WhiteCrow v{__version__}[/]  [dim]OSINT Investigation Tool[/]\n\n{art}",
                style="bright_white",
            )
            live.update(t)
            time.sleep(0.1)
